import{c as i,a7 as a,y as t,B as p}from"./chunks/framework.3cjvm90C.js";const h=JSON.parse('{"title":"Wide & Deep","description":"Wide & Deep 推荐模型的架构原理与实现","frontmatter":{"title":"Wide & Deep","description":"Wide & Deep 推荐模型的架构原理与实现"},"headers":[],"relativePath":"dlwiki/recommender/wide_deep.md","filePath":"dlwiki/recommender/wide_deep.md","lastUpdated":1782456021000}'),r={name:"dlwiki/recommender/wide_deep.md"};function n(m,e,d,o,l,s){return a(),t("div",null,[...e[0]||(e[0]=[p('<h1 id="wide-deep" tabindex="-1">Wide &amp; Deep <a class="header-anchor" href="#wide-deep" aria-label="Permalink to “Wide &amp; Deep”">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h2><p>与传统搜索类似，推荐系统的一个挑战是如何同时获得推荐结果准确性和扩展性。推荐的内容都是精准内容，用户兴趣收敛，无新鲜感，不利于长久的用户留存；推荐内容过于泛化，用户的精准兴趣无法得到满足，用户流失风险很大。相比较推荐的准确性，扩展性倾向与改善推荐系统的多样性。</p><p>Wide &amp; Deep 的主要特点: 本文提出 Wide &amp; Deep 模型，旨在使得训练得到的模型能够同时获得记忆（memorization）和泛化（generalization）能力：</p><ul><li><p><strong>记忆（memorization）即从历史数据中发现 item 或者特征之间的相关性；哪些特征更重要——Wide 部分</strong>。</p></li><li><p><strong>泛化（generalization）即相关性的传递，发现在历史数据中很少或者没有出现的新的特征组合；——Deep 部分</strong>。 在推荐系统中，记忆体现的准确性，而泛化体现的是新颖性。</p></li></ul><p><img src="https://miro.medium.com/max/1794/1*jqa4JTOUb_xUhG5Tqapo4A.png" alt="img"></p><p>首先，他模型發展的目標主要是希望解決檢索排序問題，並達到 Memorization 以及 Generalization。</p><p>Memorization 主要的定義其實就是透過<strong>歷史資料</strong>進行學習，透過歷史曾經發生的關係，達到精準預測(將歷史資料發揮淋漓盡致)。</p><p>Generalization 主要的定義是希望透過這個模型找到新的特徵組合，而過去很少發生，因此此模型主要是增加預測結果的 diversity。 <img src="https://miro.medium.com/max/1760/1*n4DZ8MTeBvUuZJFkWbskYQ.png" alt="img"></p><h2 id="wide-model" tabindex="-1">wide model <a class="header-anchor" href="#wide-model" aria-label="Permalink to “wide model”">​</a></h2><p>此篇的寬模型，主要是使用 GLM 中的 LR(經典的 CTR 預測模型)。優點是模型簡單、Scalable(Spark MLlib 已經有開源，可直接 call api)、可解釋性等優點。所以工程師可以專注於處理特徵，打造特徵海(寬的原因)。常使用 One -hot encoding 作為 feature、且可使用一些無直接相關的特徵(Ex: 安裝 app 類別)。</p><p><img src="https://miro.medium.com/max/1876/1*nRVv6DZSJxJZ3r_2OOnRQw.png" alt="img"></p><h2 id="deep-model" tabindex="-1">Deep Model <a class="header-anchor" href="#deep-model" aria-label="Permalink to “Deep Model”">​</a></h2><p>此篇的深模型，主要是使用 DNN，而他使用的方式先將大量高維度的矩陣先映射到 Embedding layer，希望透過這個方式能找到一些隱藏特徵。這樣的模型有一個很大的優點就是減少工程師花在特徵工程的時間。缺點的部分就是因為將高維度映射到一個較低維度的 Embedding layer，也就是說透過 32 維度來表示可能原來 1 萬維度的是否安裝什麼樣的 app 這個維度。致使一些資訊合併，讓某些 item 或者 niche item 無法被預測。而這樣的 Model 常使用一些 Cross product feature 於推薦系統。</p><h2 id="model" tabindex="-1">Model <a class="header-anchor" href="#model" aria-label="Permalink to “Model”">​</a></h2><p><img src="https://miro.medium.com/max/1746/1*5by4IMuXb2ELbg3vpVwLIw.png" alt="img"></p><h3 id="wide-部分" tabindex="-1">Wide 部分 <a class="header-anchor" href="#wide-部分" aria-label="Permalink to “Wide 部分”">​</a></h3><p>Wide Model 主要是使用 Logistic Regression，一般來說就是權重 X 特徵＋偏差，並丟入 sigmoid function，最後就是預測是否的機率。在文章中，主要是使用 cross product feature(Ex: 是否安裝 app 以及接下來點擊什麼樣的 app)，與前面 wide model 的任務呼應，就是希望找出新的產品組合，此外就是增加一些非線性。</p><p><img src="https://miro.medium.com/max/60/1*IrDb_zWWJNGGUSJbztFYJQ.png?q=20" alt="img"></p><p><img src="https://miro.medium.com/max/1856/1*IrDb_zWWJNGGUSJbztFYJQ.png" alt="img"></p><p>Wide Model optimizer</p><p>其中 LR 的 optimizer 跟過去不一樣，過去都是使用 SGD，而在 Wide Model 他是使用 2013 Google 在 KDD 上發表的文章(FTRL 更早就有被發表)，FTRL 主要是對 gradient 進行微調，在 Wt+1 step 中，對第一步跟當下算出來的 weight 進行 minnium，也就是說希望新的解跟當下算出來的解不要差太遠，讓 gradient 步伐小一點。此外他也要加入 L1 regularization，讓找出的解稀疏一點。</p><p>wide 部分就是一个广义线性模型，输入主要由两部分，一部分是原始特征，另一部分是交互特征，我们可以通过 cross-product transformation 的形式来构造 K 组交互特征：</p><p>$$ \\phi _ { k } ( \\mathbf { x } ) = \\prod _ { i = 1 } ^ { d } x _ { i } ^ { c _ { k i } } \\quad c _ { k i } \\in { 0,1 } $$</p><h3 id="deep-部分" tabindex="-1">Deep 部分 <a class="header-anchor" href="#deep-部分" aria-label="Permalink to “Deep 部分”">​</a></h3><p>Deep 部分就是一个 DNN 的模型，每一层计算如下： $$ a ^ { ( l + 1 ) } = f \\left( W ^ { ( l ) } a ^ { ( l ) } + b ^ { ( l ) } \\right) $$</p><p><img src="https://miro.medium.com/max/1872/1*w5R7I4kGxTlHTXGTADrEVg.png" alt="img"></p><p>Deep Neural Network，跟過去的類神經很相似，只是將其中的 hidden layer 不斷疊深。feature 的部分，此篇主要使用 numeric or one-hot encoding 的 feature。</p><p><img src="https://miro.medium.com/max/1882/1*IGYMyRCR8HrBCeKLmDvwYw.png" alt="img"></p><h3 id="activation-function" tabindex="-1">activation function <a class="header-anchor" href="#activation-function" aria-label="Permalink to “activation function”">​</a></h3><p>過去 DNN 使用的 activation function，主要為 sigmoid function ，而 sigmoid function 最大的問題就是會有 gradient vanishing，因為當我們的 gradient 算出來例如：10000，但放入 sigmoid function，他會被壓縮，最大值頂多就是 1，許多 gradient vanishing。因此，當我每進一次 sigmoid function，gradient 就會衰減一次。很可能最後訓練出來的結果會在 local min 就停下來，因為 gradient 太小趨近於 0。</p><p><img src="https://miro.medium.com/max/1706/1*9mAT6rMsechcWZYH0nIn3g.png" alt="img"></p><h3 id="dnn-optimizer" tabindex="-1">DNN optimizer <a class="header-anchor" href="#dnn-optimizer" aria-label="Permalink to “DNN optimizer”">​</a></h3><p>文章中，DNN 使用的 optimizer 是 adagrad，他主要概念為所有權重應該要有不同的 learning rate。從公式可知，在 graident 大的時候走慢一點(變化很大)，gradient 小的時候走快一點(變化不大)。</p><h3 id="联合训练" tabindex="-1">联合训练 <a class="header-anchor" href="#联合训练" aria-label="Permalink to “联合训练”">​</a></h3><p>Wide &amp; Deep 模型采用的是联合训练的形式，而非集成。二者的区别就是联合训练公用一个损失函数，然后同时更新各个部分的参数，而集成方法是独立训练 N 个模型，然后进行融合。因此，模型的输出为： $$ P ( Y = 1 | \\mathbf { x } ) = \\sigma \\left( \\mathbf { w } _ { w i d e } ^ { T } [ \\mathbf { x } , \\phi ( \\mathbf { x } ) ] + \\mathbf { w } _ { d e e p } ^ { T } a ^ { \\left( l _ { f } \\right) } + b \\right) $$</p><p><img src="https://miro.medium.com/max/1838/1*GbT163Ua3iWd83KB4PzUmg.png" alt="img"></p><p>此篇最重要的概念之一就是他的權重是同時更新，而不是像是 ensemble 一樣各自學習，然後投票出最後的結果。</p><p><img src="https://miro.medium.com/max/1848/1*Pebw0Gc5AoO6vDzfLUUO-g.png" alt="img"></p><h3 id="system-implement" tabindex="-1">system implement <a class="header-anchor" href="#system-implement" aria-label="Permalink to “system implement”">​</a></h3><p>在整個 app recommendation pipeline，它分為三大項，Data Generate, Model train 以及 Model serving。Data Generate 的部分主要是做資料前處理，像是 one — hot encoding , 字串轉換以及離散化。Model train 的部分就是他會做 online learning，只要有新的資料進來，他就會將過去的權重拿出來，繼續學習微調權重。Model serving 的部分是希望能在 10ms 去做 response，因此他們使用 multithreading 以及 batch 設定進行加速。</p><h2 id="experiment" tabindex="-1">Experiment <a class="header-anchor" href="#experiment" aria-label="Permalink to “Experiment”">​</a></h2><p><img src="https://miro.medium.com/max/60/1*au-Qg-K8-VDp_nSC9hWbaw.png?q=20" alt="img"></p><p><img src="https://miro.medium.com/max/1774/1*au-Qg-K8-VDp_nSC9hWbaw.png" alt="img"></p><p>Experiment</p><p>最後 Google 有在 google play 上實做測試，並使用 A/B test 進行模型驗證。可發現 offline 的 auc 測出來結果並沒有太大差異。但在線上的收益卻是有較大的成長。而他們認為線上測試，可以隨時有新的資料組合產生，進而去學習。</p><h2 id="使用-wide-and-deep-模型的-app-推荐系统架构" tabindex="-1">使用 Wide and Deep 模型的 App 推荐系统架构 <a class="header-anchor" href="#使用-wide-and-deep-模型的-app-推荐系统架构" aria-label="Permalink to “使用 Wide and Deep 模型的 App 推荐系统架构”">​</a></h2><p>当一个用户访问 app 商店时，此时会产生一个请求，请求到达推荐系统后，推荐系统为该用户返回推荐的 apps 列表。 <img src="https://fuhailin.github.io/https://gitee.com/fuhailin/Object-Storage-Service/raw/master/wide_and_deep_overview.png" alt="img"></p><p>在实际的推荐系统中，通常将推荐的过程分为两个部分，即上图中的 Retrieval 和 Ranking，Retrieval 负责从数据库中检索出与用户相关的一些 apps，Ranking 负责对这些检索出的 apps 打分，最终，按照分数的高低返回相应的列表给用户。</p><p>模型的训练之前，最重要的工作是训练数据的准备以及特征的选择，在 apps 推荐中，可以使用到的数据包括用户和曝光数据。 每一条样本对应了一条曝光数据，同时，样本的标签为 1 表示安装，0 则表示未安装。</p><p>对于类别特征，通过词典（Vocabularies）将其映射成向量；对于连续的实数特征，将其归一化到区间[0,1]。</p><p><img src="https://gitee.com/fuhailin/Object-Storage-Service/raw/master/wide_and_deep_structure.png" alt="img"></p>',52)])])}const g=i(r,[["render",n]]);export{h as __pageData,g as default};
